/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(VendPurchOrderJournal, PurchaseOrderConfirmation), FormControlEventType::Clicked)]
public static void Test_OnClicked(FormControl sender, FormControlEventArgs e)
{




    VendPurchOrderJour         VendPurchOrderJour;
    SrsReportRunController reportRunController;
    SrsReportRunImpl        srsReportRun;
    PurchPurchaseOrderContract dataContract;
    Args args = new args();


    reportRunController = new SrsReportRunController();

    FormButtonControl callerButton = sender as FormButtonControl;      
    FormRun form = callerButton.formRun(); 

    FormDataSource VendPurchOrderJour_ds = form.dataSource(formDataSourceStr(VendPurchOrderJournal, VendPurchOrderJour)) as FormDataSource;
    VendPurchOrderJour = VendPurchOrderJour_ds.cursor();
    dataContract = new  PurchPurchaseOrderContract();
    reportRunController.parmReportName(ssrsReportStr(PurchPurchaseOrderETG,OrderPurchaseReportFr));
    reportRunController.parmShowDialog(false);
    dataContract = reportRunController.parmReportContract().parmRdpContract() as PurchPurchaseOrderContract;
    dataContract.parmRecordId(VendPurchOrderJour.RecId);
    srsReportRun = reportRunController.parmReportRun() as SrsReportRunImpl;
    reportRunController.parmShowDialog(false);
    reportRunController.parmReportRun(srsReportRun);
    reportRunController.parmDialogCaption("Confirmation");
    reportRunController.parmReportContract().parmPrintSettings().printMediumType(SRSPrintMediumType::Screen);
    reportRunController.startOperation();



}

